const payload = $input.first().json.body || {};
const inputDir = String(payload.input_dir || '').replace(/\/+$/, '');
if (!inputDir) {
  throw new Error('input_dir 是必填项');
}

return [{
  json: {
    api_base_url: payload.api_base_url || 'http://192.168.2.26:8666/api/v1',
    input_dir: inputDir,
    clean_output_dir: payload.clean_output_dir || `${inputDir}/cleaned_dataset`,
    aggregated_output_dir: payload.aggregated_output_dir || `${inputDir}/dataset`,
    images_dir_name: payload.images_dir_name || 'images',
    xmls_dir_name: payload.xmls_dir_name || 'xmls',
    labels_dir_name: payload.labels_dir_name || 'labels',
    backgrounds_dir_name: payload.backgrounds_dir_name || 'backgrounds',
    include_difficult: payload.include_difficult ?? false,
    copy_files: payload.copy_files ?? true,
    overwrite: payload.overwrite ?? true
  }
}];

const data = $input.first().json;
if (!data.total_leaf_dirs || data.total_leaf_dirs <= 0) {
  throw new Error(`未发现可处理的叶子目录: ${$node["Prepare Config"].json.input_dir}`);
}
return [{
  json: {
    total_leaf_dirs: data.total_leaf_dirs,
    leaf_dirs: data.leaf_dirs,
  },
}];

const data = $input.first().json;
const config = $node["Prepare Config"].json;
const leafDirs = Array.isArray(data.leaf_dirs) ? data.leaf_dirs : [];
const xmlDirNames = new Set([config.xmls_dir_name, 'xml'].filter(Boolean));
const reservedLeafNames = new Set([
  config.images_dir_name,
  config.xmls_dir_name,
  'xml',
  config.labels_dir_name,
  config.backgrounds_dir_name,
].filter(Boolean));

const splitGroups = new Map();
let nonReservedLeafCount = 0;

for (const rawDir of leafDirs) {
  const dir = String(rawDir || '').replace(/\/+$/, '');
  const parts = dir.split('/').filter(Boolean);
  if (!parts.length) {
    continue;
  }
  const leafName = parts[parts.length - 1];
  const parentDir = `/${parts.slice(0, -1).join('/')}`;

  if (!reservedLeafNames.has(leafName)) {
    nonReservedLeafCount += 1;
    continue;
  }

  if (!splitGroups.has(parentDir)) {
    splitGroups.set(parentDir, {
      parent_dir: parentDir,
      images_dir_name: null,
      xmls_dir_name: null,
    });
  }

  const entry = splitGroups.get(parentDir);
  if (leafName === config.images_dir_name) {
    entry.images_dir_name = leafName;
  }
  if (xmlDirNames.has(leafName)) {
    entry.xmls_dir_name = leafName;
  }
}

const splitFragmentDirs = Array.from(splitGroups.values()).filter((entry) => entry.images_dir_name && entry.xmls_dir_name);
const layoutMode = splitFragmentDirs.length > 0 && nonReservedLeafCount === 0
  ? 'split_images_xml_dirs'
  : 'mixed_leaf_files';

return [{
  json: {
    total_leaf_dirs: data.total_leaf_dirs,
    leaf_dirs: leafDirs,
    layout_mode: layoutMode,
    split_fragment_count: splitFragmentDirs.length,
    split_fragment_dirs: splitFragmentDirs,
    non_reserved_leaf_count: nonReservedLeafCount,
  },
}];

